let assets = 
    corelight_asset_classification
    | where ('*' in ({Sensor}) or sensor_name in ({Sensor}))
    | where ('*' in ({OSName}) or os_name in ({OSName}))
    | where ('*' in ({TypeGroup}) or type_group in ({TypeGroup}))
    | where ('*' in ({TypeName}) or type_name in ({TypeName}))
    | where ('*' == '{IPAddress}' or ip == '{IPAddress}')
    | where isnotempty(device_type)
    | summarize device_type = any(device_type) by ip;
corelight_conn
| join kind=inner (assets) on $left.src_ip == $right.ip
| extend total_bytes = coalesce(toreal(orig_bytes), real(0)) + coalesce(toreal(resp_bytes), real(0))
| make-series Bytes = sum(total_bytes) default = 0 
    on TimeGenerated 
    from start_time 
    to end_time 
    step bin_duration 
    by device_type

